func solve(matrix [][]int64) []int64 {
    n := len(matrix)
    ans := make([]int64, n)

    for i := 0; i < n; i++ {
        degree := int64(0)
        for j := 0; j < n; j++ {
            // In an adjacency matrix for an undirected graph, matrix[i][j] = 1 means an edge exists.
            // Since the matrix is symmetric and matrix[i][i] = 0 (no self-loops), 
            // we just need to count the number of 1s in the i-th row (or i-th column).
            if matrix[i][j] == 1 {
                degree++
            }
        }
        ans[i] = degree
    }

    return ans
}
